public sealed partial class WebSearchTool(HttpClient httpClient)
{
    private static readonly JsonSerializerOptions s_jsonOptions = new() { PropertyNameCaseInsensitive = true };

    [Description("Searches the web for a query and returns a list of relevant results with titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

