                : "";

            if (!string.IsNullOrWhiteSpace(title) && href.StartsWith("http", StringComparison.Ordinal))
            {
                results.Add(new SearchResult(title, href, snippet));
            }
        }

        return results;
    }

    private static string ExtractTextFromHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Remove HTML tags
        cleaned = HtmlTagRegex().Replace(cleaned, " ");
        // Decode HTML entities
        cleaned = WebUtility.HtmlDecode(cleaned);
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();
        return cleaned;
    }

