+using System.ComponentModel;
+using System.Net;
+using System.Text.Json;
+using System.Text.RegularExpressions;
+
+namespace ResearchAgent.Tools;
+
+/// <summary>
+/// Provides web search and page-fetching capabilities for the research agent.
+/// Uses DuckDuckGo for search and HttpClient for page retrieval.
+/// </summary>
+public sealed partial class WebSearchTool(HttpClient httpClient)
+{
+    private static readonly JsonSerializerOptions s_jsonOptions = new() { PropertyNameCaseInsensitive = true };
+
+    [Description("Searches the web for a query and returns a list of relevant results with titles, URLs, and snippets.")]
+    public async Task<string> SearchWeb(
+        [Description("The search query")] string query,
+        CancellationToken cancellationToken = default)
+    {
+        var encoded = WebUtility.UrlEncode(query);
+        var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
+
+        using var request = new HttpRequestMessage(HttpMethod.Get, url);
+        request.Headers.Add("User-Agent", "ResearchAgent/1.0");
+
+        using var response = await httpClient.SendAsync(request, cancellationToken);
+        response.EnsureSuccessStatusCode();
+
+        var html = await response.Content.ReadAsStringAsync(cancellationToken);
+        var results = ParseSearchResults(html);
+
+        if (results.Count == 0)
+        {
+            return $"No results found for '{query}'.";
+        }
+
+        return string.Join("\n\n", results.Select((r, i) =>
+            $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
+    }
+
+    [Description("Fetches the text content of a web page at the given URL. Use this to read full articles after finding them via SearchWeb.")]
+    public async Task<string> FetchWebPage(
+        [Description("The full URL of the web page to fetch")] string url,
+        CancellationToken cancellationToken = default)
+    {
+        using var request = new HttpRequestMessage(HttpMethod.Get, url);
+        request.Headers.Add("User-Agent", "ResearchAgent/1.0");
+        request.Headers.Add("Accept", "text/html");
+
+        using var response = await httpClient.SendAsync(request, cancellationToken);
+        response.EnsureSuccessStatusCode();
+
+        var html = await response.Content.ReadAsStringAsync(cancellationToken);
+        var text = ExtractTextFromHtml(html);
+
+        const int maxLength = 4000;
+        if (text.Length > maxLength)
+        {
+            text = text[..maxLength] + "\n\n[Content truncated — use SearchWeb for additional sources]";
+        }
+
+        return text;
+    }
+
+    private static List<SearchResult> ParseSearchResults(string html)
+    {
+        var results = new List<SearchResult>();
+
+        // DuckDuckGo Lite returns results in a table with specific structure.
+        // Each result has a link in a <a> tag and a snippet in a <td> with class "result-snippet".
+        var linkMatches = ResultLinkRegex().Matches(html);
+        var snippetMatches = SnippetRegex().Matches(html);
+
+        for (var i = 0; i < Math.Min(linkMatches.Count, 5); i++)
+        {
+            var link = linkMatches[i];
+            var href = WebUtility.HtmlDecode(link.Groups[1].Value);
+            var title = StripHtml(link.Groups[2].Value);
+            var snippet = i < snippetMatches.Count
+                ? StripHtml(snippetMatches[i].Groups[1].Value).Trim()
+                : "";
+
+            if (!string.IsNullOrWhiteSpace(title) && href.StartsWith("http", StringComparison.Ordinal))
+            {
+                results.Add(new SearchResult(title, href, snippet));
+            }
