using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to record findings.
/// Notes persist in memory for the lifetime of the application.
/// </summary>
public sealed class NoteService
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note. Use this to record important findings, facts, or insights discovered during research.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        var note = new Note(title, content, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note saved: '{title}' (total notes: {_notes.Count})";
    }

    [Description("Retrieves all saved research notes. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}\n[Saved at {n.SavedAt:u}]"));
    }

    private sealed record Note(string Title, string Content, DateTime SavedAt);
}

