using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Build the MEAI chat client through the provider SDK
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Create tool instances
var noteService = new NoteService();
using var httpClient = new HttpClient();
var webSearch = new WebSearchTool(httpClient);

// Register tools with explicit schemas
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchWebPage),
    AIFunctionFactory.Create(noteService.SaveNote),
    AIFunctionFactory.Create(noteService.GetNotes),
};

// Create the research agent with guardrails
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research assistant. When given a topic:
        1. Use SearchWeb to find relevant sources on the topic.
        2. Use FetchWebPage to read the most promising results in detail.
        3. Use SaveNote to record each key finding — include the source URL.
        4. Repeat steps 1-3 with refined queries to cover different angles.
        5. Use GetNotes to review all your findings.
        6. Provide a well-structured summary with sections, key facts, and source citations.

        Be methodical: search, read, take notes, then summarize.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking",
    tools: tools);

Console.WriteLine("🔬 Research Agent");
Console.WriteLine("Enter a topic to research, or 'quit' to exit.");
Console.WriteLine(new string('─', 50));

while (true)
{
    Console.Write("\nTopic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    Console.WriteLine($"\n📚 Researching: {topic}\n");

    try
    {
        var session = await agent.CreateSessionAsync();
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session);

        Console.WriteLine(response.Text);
    }
    catch (Exception ex)
    {
        Console.WriteLine($"❌ Error: {ex.Message}");
    }
}

Console.WriteLine("\nGoodbye!");

